// src/security/input-validator.ts
export class InputValidator {
  private static MAX_INPUT_LENGTH = 10000;
  private static PATH_WHITELIST = ['/tmp', '/workspace'];

  static validate(input: string, options?: ValidationOptions): ValidationResult {
    // 长度检查
    if (input.length > this.MAX_INPUT_LENGTH) {
      return { valid: false, error: '输入过长' };
    }

    // 危险字符检查
    const dangerous = ['../', '~/', '$(', '`'];
    if (dangerous.some(char => input.includes(char))) {
      return { valid: false, error: '包含危险字符' };
    }

    return { valid: true };
  }

  static sanitizePath(path: string): string {
    // 路径规范化
    const normalized = path.normalize(path);

    // 确保在白名单内
    if (!this.isPathAllowed(normalized)) {
      throw new SecurityError('路径不在允许范围内');
    }

    return normalized;
  }

  static escapeCommand(cmd: string): string {
    // 转义shell命令参数
    return cmd.replace(/([^a-zA-Z0-9_.-])/g, '\\$1');
  }
}

// 使用示例
class AgentExecutor {
  async executeFileOperation(filePath: string) {
    // 验证输入
    const validation = InputValidator.validate(filePath);
    if (!validation.valid) {
      throw new SecurityError(validation.error);
    }

    // 消毒路径
    const safePath = InputValidator.sanitizePath(filePath);

    // 安全执行
    return await fs.readFile(safePath);
  }
}
```

**验收标准**:
- ✅ 阻止所有已知攻击向量
