// src/agents/security/resource-limits.ts
export class ResourceLimits {
  private readonly MAX_MEMORY = 500 * 1024 * 1024; // 500MB
  private readonly MAX_EXECUTION_TIME = 5 * 60 * 1000; // 5分钟
  private readonly MAX_API_CALLS = 100; // 每小时

  async checkMemoryUsage(): Promise<void> {
    const usage = process.memoryUsage();
    if (usage.heapUsed > this.MAX_MEMORY) {
      throw new Error('内存使用超限');
    }
  }

  async withTimeout<T>(
    fn: () => Promise<T>,
    timeout: number = this.MAX_EXECUTION_TIME
  ): Promise<T> {
    return Promise.race([
      fn(),
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error('执行超时')), timeout)
      )
    ]);
  }

  async withRateLimit<T>(
    fn: () => Promise<T>
  ): Promise<T> {
    // 实现速率限制
    const key = `rate_limit:${this.agentName}`;
    const count = await redis.incr(key);

    if (count === 1) {
      await redis.expire(key, 3600); // 1小时过期
    }

    if (count > this.MAX_API_CALLS) {
      throw new Error('API调用次数超限');
    }

    return fn();
  }
}
```

