// src/dashboard/services/realtime.service.ts
export class RealtimeService {
  private clients: Set<WebSocket> = new Set()
  private subscriptions: Map<string, Set<WebSocket>> = new Map()

  /**
   * 订阅频道
   */
  subscribe(client: WebSocket, channel: string) {
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set())
    }
    this.subscriptions.get(channel)!.add(client)

    this.logger.info('Client subscribed to channel', { channel })
  }

  /**
   * 取消订阅
   */
  unsubscribe(client: WebSocket, channel: string) {
    const subscribers = this.subscriptions.get(channel)
    if (subscribers) {
      subscribers.delete(client)
    }
  }

  /**
   * 广播消息到所有订阅者
   */
  broadcast(event: string, data: any, channel?: string) {
    const message = JSON.stringify({ event, data, timestamp: Date.now() })

    if (channel) {
      const subscribers = this.subscriptions.get(channel)
      if (subscribers) {
        subscribers.forEach(client => {
          if (client.readyState === WebSocket.OPEN) {
            client.send(message)
          }
        })
      }
    } else {
      // 广播到所有客户端
      this.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message)
        }
      })
    }

    this.logger.info('Broadcasted event', { event, channel })
  }

  /**
   * 启动心跳检测
   */
  startHeartbeat() {
    setInterval(() => {
      const message = JSON.stringify({
        event: 'heartbeat',
        timestamp: Date.now()
      })

      this.clients.forEach(client => {
        if (client.readyState === WebSocket.OPEN) {
          client.send(message)
        }
      })
    }, 30000) // 30秒
  }
}
