// src/auto-iteration.ts
import { DashboardIntegrationService } from './dashboard/integration/dashboard-integration'

export class AutoIterationEngine {
  private dashboard: DashboardIntegrationService

  constructor(config: any) {
    // ... 现有代码
    this.dashboard = new DashboardIntegrationService()
  }

  async start() {
    for (let i = 0; i < this.config.maxIterations; i++) {
      this.count++

      // 通知 Dashboard：迭代开始
      await this.dashboard.createIteration({
        iterationNumber: this.count,
        status: 'running',
        requirement: this.requirement || '自动发现',
        startedAt: new Date().toISOString()
      })

      // 产品经理阶段
      await this.dashboard.updateIterationProgress(this.count, 'product_manager', 10)
      const pmResult = await this.runAgent('product-manager', this.requirement)

      // 架构师阶段
      await this.dashboard.updateIterationProgress(this.count, 'architect', 20)
      const architectResult = await this.runAgent('architect', pmResult.requirement)

      // ... 其他 Agent 阶段

      // 完成迭代
      await this.dashboard.completeIteration(this.count, {
        architectResult: architectResult.output,
        frontendResult: frontendResult.output,
        // ... 其他结果
      })

      // Git 提交
      await this.gitCommit()

      // 等待下一次迭代
      await this.wait(this.config.interval)
    }
  }

  private async runAgent(name: string, task: string) {
    try {
      const agent = this.agents.find(a => a.name === name)
      if (!agent) throw new Error(`Agent ${name} not found`)

      // 通知 Dashboard：Agent 开始执行
      await this.dashboard.notifyAgentStart(this.count, name, task)

      const result = await agent.execute(task)

      // 通知 Dashboard：Agent 完成
      await this.dashboard.notifyAgentComplete(this.count, name, result)

      return result
    } catch (error: any) {
      // 通知 Dashboard：Agent 失败
      await this.dashboard.notifyAgentError(this.count, name, error.message)
      throw error
    }
  }
}
