export abstract class BaseAgent {
  /**
   * 带超时控制的执行
   */
  async executeWithTimeout(task: string, timeoutMs: number = 300000) {
    return Promise.race([
      this.execute(task),
      new Promise((_, reject) => 
        setTimeout(() => reject(new Error('Agent execution timeout')), timeoutMs)
      )
